            flex-direction: column;
            align-items: center;
            padding: 20px;
            background-color: #f4f4f9;
        }

        #spreadsheet-container {
            display: grid;
            /* Grid structure for headers and cells */
            grid-template-columns: 50px repeat(10, 1fr); /* Column A (Header) + J columns */
            grid-auto-rows: 30px; /* Row height */
            border: 1px solid #ccc;
            box-shadow: 2px 2px 5px rgba(0, 0, 0, 0.1);
            background-color: white;
        }

        /* Corner cell (empty) */
        #spreadsheet-container > :first-child {
            background-color: #eee;
            border: none;
            z-index: 0;
        }

        /* Column Headers (A, B, C...) */
        .col-header {
            grid-column: span 1;
            text-align: center;
            font-weight: bold;
            background-color: #e9ecef;
            border-right: 1px solid #ccc;
            cursor: default;
            padding: 5px 0;
        }

        /* Row Headers (1, 2, 3...) */
        .row-header {
            grid-row: span 1;
            text-align: center;
            font-weight: bold;
            background-color: #e9ecef;
            border-bottom: 1px solid #ccc;
            cursor: default;
            padding: 5px 0;
